/**
 * Initialize Envelope (TVPX__60)
 * Minimal schema to import reliably.
 */
function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

const incoming = $json || {};
const now = new Date().toISOString();
const baseCtx = (incoming.ctx && typeof incoming.ctx === 'object') ? incoming.ctx : {};

const traceId = String(baseCtx.trace_id || '').trim() || `tvpx_${fnv1a(JSON.stringify(incoming).slice(0, 4000) + '::' + now)}`;

const ctx = {
  project_ns: 'TVPX',
  brand_name: 'The Velvet Paradox',
  trace_id: traceId,
  trigger_mode: baseCtx.trigger_mode || 'internal',
  route_mode: 'video_seed_prepare',
  received_at: now
};

return [{ json: { ctx, input: incoming.input || incoming } }];

/**
 * Reattach Context After Seed Fetch
 * Emits one item per seed: { ctx, seed }
 */
const base = $items('Initialize Envelope')[0].json;
const ctx = base.ctx;
const rows = $input.all().map(i => i.json);

return rows.map(r => ({ json: { ctx, seed: r } }));

const current = $items('Reattach Context After Seeds', 0, 0)[$itemIndex]?.json || {};
const ctx = current.ctx || {};
const seed = current.seed || {};
const assetRow = $items('Get Source Asset', 0, 0)[$itemIndex]?.json || {};
const sceneSeedRow = $items('Get Source Scene Seed', 0, 0)[$itemIndex]?.json || {};
const sceneBlueprintRow = $items('Get Source Scene Blueprint', 0, 0)[$itemIndex]?.json || {};
const archetypeRow = $items('Get Source Archetype', 0, 0)[$itemIndex]?.json || {};

if (!assetRow || !Object.keys(assetRow).length) throw new Error('TVPX__60: source asset row missing.');
if (!sceneSeedRow || !Object.keys(sceneSeedRow).length) throw new Error('TVPX__60: source scene seed row missing.');

const stillUrl = String(seed.still_image_drive_url || assetRow.drive_view_url || assetRow.drive_download_url || assetRow.provider_image_url || '').trim();
if (!stillUrl) throw new Error('TVPX__60: missing still image URL.');

const guardrails = {
  pace: 'slow',
  camera: ['glide', 'hover', 'micro-dolly'],
  preserve: [
    'composition identity',
    'archetype family',
    'lighting mood',
    'tactile textures',
    'negative space as pressure',
    'real-world optics',
    'believable anatomy',
    'natural skin texture',
    'cloth and hair physics',
  ],
  avoid: [
    'scene changes',
    'fast cuts',
    'hyperactive motion',
    'rubbery morphing',
    'new objects',
    'breaking the singular focal point',
    'temporal face drift',
    'plastic skin',
    'cg sheen',
  ],
};

return [{
  json: {
    ctx,
    seed,
    asset: assetRow,
    scene_seed: sceneSeedRow,
    scene_blueprint: sceneBlueprintRow,
    archetype: archetypeRow,
    motion_brief: {
      still_reference_url: stillUrl,
      scene_seed_id: String(seed.scene_seed_id || sceneSeedRow.scene_seed_id || '').trim(),
      scene_blueprint_id: String(seed.scene_blueprint_id || sceneBlueprintRow.scene_blueprint_id || '').trim(),
      archetype_id: String(seed.archetype_id || archetypeRow.archetype_id || sceneSeedRow.archetype_id || '').trim(),
      operator_motion_hint: String(seed.motion_prompt || '').trim(),
      scene_kernel: String(sceneSeedRow.scene_kernel || '').trim(),
      symbolic_tension: String(sceneSeedRow.symbolic_tension || '').trim(),
      spatial_directive: String(sceneSeedRow.spatial_directive || '').trim(),
      palette_directive: String(sceneSeedRow.palette_directive || '').trim(),
      texture_directive: String(sceneSeedRow.texture_directive || '').trim(),
      blueprint: sceneBlueprintRow,
      archetype: archetypeRow,
      guardrails,
    },
  },
}];

